const body = $input.first().json.body || $input.first().json;
return [{
  json: {
    req_id: body.req_id,
    title: body.title,
    description: body.description || '',
    scope: body.scope || 'server-go',
    repo: body.repo || '',
    github_token: body.github_token || '',
    bkd_issue_id: body.bkd_issue_id || '',
    bkd_project_id: body.bkd_project_id || 'ttposhwt',
    round: 0,
    total_tokens: 0,
    start_time: Date.now(),
    max_rounds: 3,
    max_duration_ms: 3600000,
    max_tokens: 500000
  }
}];

const resp = $input.first().json;
const headers = resp.headers || {};
const sessionId = headers['mcp-session-id'] || headers['Mcp-Session-Id'] || '';
const state = $node['Parse Request'].json;
return [{
  json: {
    ...state,
    _session_id: sessionId,
    _bkd_url: 'https://bkd-launcher--admin-jbcnet--weifashi.coder.tbc.5ok.co/api/mcp',
    _coder_token: 'GRvtsFrbNV-7fX1P2rwfDRKwnmXsSYQEn'
  }
}];

const s = $node['Parse Init'].json;
return [{
  json: {
    projectId: 'ttposhwt',
    title: '[' + s.req_id + '] P0 Contract Design',
    prompt: 'Requirement ' + s.req_id + ': ' + s.title + '\n\nDescription: ' + s.description + '\nScope: ' + s.scope + '\n\nTask: Design the API contract for this requirement.\n- Define endpoint paths, methods, request/response schemas\n- Output as contract.spec.yaml\n- Save to the worktree\n- When done, move issue to review status',
    engineType: 'claude-code',
    tags: ['p0', s.req_id],
    timeoutMs: 900000,
    useWorktree: true
  }
}];

const s = $node['Parse Init'].json;
return [{
  json: {
    projectId: 'ttposhwt',
    title: '[' + s.req_id + '] P1 Spec Split',
    prompt: 'Requirement ' + s.req_id + ': ' + s.title + '\n\nTask: Split the contract into three specs:\n1. dev.spec.md - implementation details and unit test requirements\n2. contract.spec.yaml - API schema validation rules\n3. ac.spec.yaml - acceptance test scenarios (Given/When/Then)\n\nIMPORTANT: The ac.spec.yaml is LOCKED after this step.\n\nWhen done, move issue to review status.',
    engineType: 'claude-code',
    tags: ['p1', s.req_id],
    timeoutMs: 900000,
    useWorktree: true
  }
}];

// 从 Collect Result 或 Parse Init 获取状态
let s;
try { s = $node['Collect Result'].json; } catch(e) { s = $node['Parse Init'].json; }
const round = (s.round || 0) + 1;
return [{
  json: {
    projectId: 'ttposhwt',
    title: '[' + s.req_id + '] Dev Round ' + round,
    prompt: 'Requirement ' + s.req_id + ': ' + s.title + '
Round: ' + round + '

Task: Implement the feature based on dev.spec.md, then verify.

Steps:
1. Write code based on dev.spec.md
2. Run verification (lint, unit tests, contract tests)
3. Use aissh MCP for debug environment if needed
4. git commit and push changes
5. Report results

When complete, move issue to review.

Return JSON in your final message:
{ "success": true/false, "layer_results": {...}, "tokens_used": number, "failed_layer": null/string, "error_summary": null/string }',
    engineType: 'claude-code',
    tags: ['dev', s.req_id, 'round-' + round],
    timeoutMs: 1500000,
    useWorktree: true
  }
}];

const result = $input.first().json;
const state = $node['Parse Init'].json;
const prevRound = state.round || 0;
const elapsed = Date.now() - state.start_time;
const tokensUsed = result.output?.tokens_used || 0;
const tokens = (state.total_tokens || 0) + tokensUsed;

return [{
  json: {
    req_id: state.req_id,
    title: state.title,
    description: state.description,
    scope: state.scope,
    repo: state.repo,
    github_token: state.github_token,
    bkd_issue_id: state.bkd_issue_id,
    bkd_project_id: state.bkd_project_id,
    round: prevRound + 1,
    total_tokens: tokens,
    start_time: state.start_time,
    elapsed_ms: elapsed,
    max_rounds: state.max_rounds,
    max_duration_ms: state.max_duration_ms,
    max_tokens: state.max_tokens,
    success: result.success === true,
    layer_results: result.output?.layer_results || {},
    failed_layer: result.output?.failed_layer || null,
    error_summary: result.output?.error_summary || result.error || null,
    issueId: result.issueId,
    _session_id: state._session_id,
    _bkd_url: state._bkd_url,
    _coder_token: state._coder_token
  }
}];

const s = $node['Collect Result'].json;
const tripped = (
  s.round >= s.max_rounds ||
  s.elapsed_ms >= s.max_duration_ms ||
  s.total_tokens >= s.max_tokens
);
const reason = [];
if (s.round >= s.max_rounds) reason.push('rounds ' + s.round + '/' + s.max_rounds);
if (s.elapsed_ms >= s.max_duration_ms) reason.push('time ' + Math.round(s.elapsed_ms/1000) + 's');
if (s.total_tokens >= s.max_tokens) reason.push('tokens ' + s.total_tokens + '/' + s.max_tokens);
return [{
  json: {
    ...s,
    breaker_tripped: tripped,
    breaker_reason: reason.join(', ') || 'none'
  }
}];

// 更新 Parse Init 的状态用于下一轮
const s = $node['Collect Result'].json;
return [{ json: s }];

